option.value:
@import url("https://fonts.googleapis.com/css2?family=Barlow+Condensed:wght@400;600;700;800;900&family=Barlow:wght@400;500;600;700&display=swap");

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  width: 100%;
  height: 100%;
}

body {
  margin: 0;
  width: 100%;
  height: 100%;
  background: #08080f;
  font-family: "Barlow Condensed", "Barlow", "Segoe UI", sans-serif;
  color: #e2e8f0;
  -webkit-font-smoothing: antialiased;
  overflow: hidden;
}

#root {
  display: flex;
  flex-direction: column;
  width: 100%;
  min-width: 100%;
  max-width: none;
  height: 100%;
  min-height: 100vh;
  min-height: 100dvh;
}

button,
input,
select {
  font-family: inherit;
}

/* Satu shell fullscreen — tanpa max-width */
.admin-app {
  display: flex;
  flex-direction: column;
  flex: 1;
  width: 100%;
  min-width: 0;
  min-height: 0;
  height: 100%;
  background: #08080f;
  overflow: hidden;
}

.admin-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-shrink: 0;
  width: 100%;
  padding: 0 28px;
  height: 54px;
  background: rgba(5, 5, 12, 0.98);
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
}

.admin-main {
  flex: 1;
  display: flex;
  flex-direction: column;
  width: 100%;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
}

/* Semua halaman mengisi area konten */
.admin-page {
  flex: 1;
  width: 100%;
  min-width: 0;
  padding: 28px 32px;
  overflow-y: auto;
  overflow-x: hidden;
}

.admin-grid-4 {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 16px;
}

.admin-grid-3 {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 16px;
}

.admin-grid-2 {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 20px;
}

.nav-tab {
  background: none;
  border: none;
  color: #888;
  border-radius: 8px;
  padding: 7px 14px;
  font-size: 12;
  font-weight: 400;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 6px;
  letter-spacing: 0.5px;
}

.nav-tab--active {
  background: rgba(255, 107, 53, 0.12);
  color: #ff6b35;
  font-weight: 700;
}

.avatar {
  width: 32px;
  height: 32px;
  border-radius: 16px;
  background: linear-gradient(135deg, #ff6b35, #f7c59f);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 14px;
  font-weight: 700;
  color: #fff;
}

.notif-badge {
  position: absolute;
  top: -2px;
  right: -2px;
  width: 14px;
  height: 14px;
  border-radius: 7px;
  background: #fc8181;
  font-size: 9px;
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
}

select option {
  background: #1a1a2e;
  color: #fff;
}

/* ─── Login ─── */
.login-page {
  min-height: 100vh;
  min-height: 100dvh;
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  background: radial-gradient(ellipse at 30% 20%, rgba(255, 107, 53, 0.12), transparent 50%),
    radial-gradient(ellipse at 80% 80%, rgba(99, 179, 237, 0.08), transparent 40%), #030308;
  padding: 24px;
}

.login-card {
  width: 100%;
  max-width: 420px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 20px;
  padding: 40px 36px;
  box-shadow: 0 40px 100px rgba(0, 0, 0, 0.6);
}

.login-brand {
  text-align: center;
  margin-bottom: 8px;
}

.login-brand-nusa {
  font-size: 22px;
  font-weight: 900;
  letter-spacing: 3px;
}

.login-brand-vision {
  font-size: 22px;
  font-weight: 900;
  letter-spacing: 3px;
  color: #ff6b35;
}

.login-brand-sub {
  font-size: 10px;
  color: #555;
  letter-spacing: 4px;
  margin-top: 6px;
  font-family: monospace;
}

.login-desc {
  text-align: center;
  font-size: 13px;
  color: #888;
  margin: 0 0 28px;
  line-height: 1.5;
}

.login-form {
  display: flex;
  flex-direction: column;
  gap: 18px;
}

.login-label {
  display: flex;
  flex-direction: column;
  gap: 8px;
  font-size: 10px;
  color: #888;
  letter-spacing: 1px;
  font-weight: 700;
}

.login-input {
  width: 100%;
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(255, 255, 255, 0.12);
  border-radius: 10px;
  color: #fff;
  font-size: 14px;
  padding: 12px 14px;
  outline: none;
  box-sizing: border-box;
}

.login-input:focus {
  border-color: rgba(255, 107, 53, 0.5);
}

.login-pass-wrap {
  position: relative;
}

.login-pass-wrap .login-input {
  padding-right: 44px;
}

.login-pass-toggle {
  position: absolute;
  right: 10px;
  top: 50%;
  transform: translateY(-50%);
  background: none;
  border: none;
  cursor: pointer;
  font-size: 16px;
  opacity: 0.7;
}

.login-submit {
  margin-top: 8px;
  width: 100%;
  background: #ff6b35;
  border: none;
  border-radius: 10px;
  color: #fff;
  font-size: 14px;
  font-weight: 800;
  padding: 14px;
  cursor: pointer;
  letter-spacing: 0.5px;
}

.login-submit:disabled {
  opacity: 0.65;
  cursor: wait;
}

.login-submit:hover:not(:disabled) {
  filter: brightness(1.08);
}

.login-error {
  padding: 10px 14px;
  background: rgba(252, 129, 129, 0.12);
  border: 1px solid rgba(252, 129, 129, 0.3);
  border-radius: 10px;
  font-size: 12px;
  color: #fc8181;
}

.login-hint {
  margin-top: 24px;
  font-size: 11px;
  color: #555;
  text-align: center;
  line-height: 1.6;
}

.login-hint code {
  color: #ff6b35;
  font-size: 10px;
}

@media (max-width: 1200px) {
  .admin-grid-4,
  .admin-grid-3 {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 768px) {
  .admin-grid-4,
  .admin-grid-3,
  .admin-grid-2 {
    grid-template-columns: 1fr;
  }
}

